CREATE TABLE forum_threads (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), author_id UUID REFERENCES users(id) ON DELETE SET NULL, title TEXT NOT NULL, body TEXT NOT NULL, body_search TSVECTOR GENERATED ALWAYS AS (to_tsvector('english', coalesce(title, '') || ' ' || coalesce(body, ''))) STORED, topic_tags TEXT[] NOT NULL DEFAULT '{}', status TEXT NOT NULL CHECK (status IN ('open', 'resolved', 'closed')) DEFAULT 'open', upvote_count INTEGER NOT NULL DEFAULT 0, reply_count INTEGER NOT NULL DEFAULT 0, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE thread_replies (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), thread_id UUID NOT NULL REFERENCES forum_threads(id) ON DELETE CASCADE, author_id UUID REFERENCES users(id) ON DELETE SET NULL, parent_reply_id UUID REFERENCES thread_replies(id) ON DELETE CASCADE, body TEXT NOT NULL, upvote_count INTEGER NOT NULL DEFAULT 0, is_hidden BOOLEAN NOT NULL DEFAULT FALSE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE thread_upvotes (user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, thread_id UUID NOT NULL REFERENCES forum_threads(id) ON DELETE CASCADE, PRIMARY KEY(user_id, thread_id));
CREATE TABLE reply_upvotes (user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, reply_id UUID NOT NULL REFERENCES thread_replies(id) ON DELETE CASCADE, PRIMARY KEY(user_id, reply_id));
